const inputData = $input.first().json;
const originalArticles = $('2. Подготовка данных для аналитики AI').first().json.articles;

const analysis = inputData.output || inputData;
if (!analysis.selected_articles) {
  throw new Error('Missing selected_articles in analysis. Available fields: ' + JSON.stringify(Object.keys(analysis)));
}

// ✅ СОРТИРОВКА СТАТЕЙ ПО ВАЖНОСТИ (от большего к меньшему)
const selectedArticles = analysis.selected_articles
  .map(selected => {
    const article = originalArticles.find(a => a.id === selected.id);
    if (!article) {
      throw new Error(`Article with id ${selected.id} not found in original articles`);
    }
    return {
      ...article,
      importance: selected.importance_score,
      reason: selected.reason,
      key_points: selected.key_points
    };
  })
  .sort((a, b) => b.importance - a.importance); // ← ДОБАВЛЕНА СОРТИРОВКА

// ✅ ПРОМПТ С УКАЗАНИЕМ ПОРЯДКА
const writingPrompt = `На основе следующего анализа создай качественный технологический лонгрид В ФОРМАТЕ MARKDOWN:

**Анализ новостной повестки:**
${analysis.analysis_summary}

**Ключевые тренды:**
${analysis.key_trends.map((t, i) => `${i + 1}. ${t}`).join('\n')}

**Группы статей по темам:**
${analysis.article_groups.map(group => `
### ${group.topic} (Важность: ${group.importance}/10)
Статьи: ${group.articles.join(', ')}
Суммари: ${group.summary}
`).join('\n')}

**Статьи для использования (в порядке убывания важности):**
${selectedArticles.map((article, index) => `
--- Новость #${index + 1} (Важность: ${article.importance}/10) ---
Заголовок: ${article.title}
URL: ${article.url}
Причина выбора: ${article.reason}
Ключевые моменты: ${article.key_points.join('; ')}

Полный текст:
${article.content}
`).join('\n\n')}

ВАЖНО: Используй нумерацию 1, 2, 3... в заголовках новостей согласно порядку выше.

Напиши профессиональный технологический лонгрид в ЧИСТОМ MARKDOWN формате.
Верни результат в формате JSON согласно схеме (title + markdown_content).`;

return {
  json: {
    writingPrompt,
    analysis,
    selectedArticlesCount: selectedArticles.length,
    totalTrends: analysis.key_trends.length
  }
};

const longreadData = $('8. Extract Gist URL').first().json.original_longread_data;
const gistUrl = $input.first().json.gist_url;
const originalArticles = $('2. Подготовка данных для аналитики AI').first().json.articles;
const analystOutput = $('3. AI Analyst').first().json.output;

// Parse markdown to extract sections for summary
const markdown = longreadData.markdown_content;
const title = longreadData.title;

// ============================================
// ФОЛЛБЭК ЛОГИКА ДЛЯ 100% НАДЁЖНОСТИ
// ============================================

// Попытка 1: Секции с нумерацией (## 1. Заголовок, ## 2. Заголовок...)
let sectionMatches = [...markdown.matchAll(/^## (\d+)\.\s*(.+)$/gm)];
let sections = sectionMatches.map(match => ({
  number: match[1],
  title: match[2]
}));

// Попытка 2: Секции БЕЗ нумерации (## Заголовок)
if (sections.length === 0) {
  sectionMatches = [...markdown.matchAll(/^## ([^#\n]+)$/gm)];
  sections = sectionMatches.map((match, index) => ({
    number: String(index + 1),
    title: match[1].trim()
  }));
}

// Попытка 3: Любые заголовки (H1, H2, H3)
if (sections.length === 0) {
  sectionMatches = [...markdown.matchAll(/^#{1,3}\s+(.+)$/gm)];
  sections = sectionMatches.map((match, index) => ({
    number: String(index + 1),
    title: match[1].replace(/^\d+\.\s*/, '').trim() // Убираем цифры из заголовка, если есть
  }));
}

// Фильтруем заключение и введение
sections = sections.filter(s => 
  !s.title.toLowerCase().includes('заключение') && 
  !s.title.toLowerCase().includes('введение')
);

// Строим сообщение
let message = `📰 *${title}*\n\n`;

// Если нашли секции — делаем краткое содержание
if (sections.length > 0) {
  message += `📊 *Краткое содержание:*\n\n`;

  sections.forEach((section, index) => {
    const emoji = ['1️⃣', '2️⃣', '3️⃣', '4️⃣', '5️⃣', '6️⃣', '7️⃣', '8️⃣', '9️⃣', '🔟'][index] || '▪️';

    // Убираем цифру из заголовка для отображения (чтобы не было "1️⃣ 1. Заголовок")
    const cleanTitle = section.title.replace(/^\d+\.\s*/, '');

    // Пробуем извлечь первый абзац после этой секции
    const escapedTitle = section.title.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const sectionRegex = new RegExp(
      `## (?:\\d+\\.\\s*)?${escapedTitle}\\s*\\n\\s*\\n([^#]+)`, 
      'm'
    );
    const sectionContent = markdown.match(sectionRegex);

    if (sectionContent && sectionContent[1]) {
      const firstPara = sectionContent[1].split('\n\n')[0];
      const sentences = firstPara.split(/[.!?]\s+/).slice(0, 2);
      const summary = sentences.join('. ').trim();
      const shortSummary = summary.length > 250 ? summary.substring(0, 247) + '...' : summary;

      message += `${emoji} *${cleanTitle}*\n`;
      message += `${shortSummary}\n\n`;
    } else {
      // Фоллбэк: если не удалось извлечь контент, просто показываем заголовок
      message += `${emoji} *${cleanTitle}*\n\n`;
    }
  });
}

// Ссылка на полный лонгрид
message += `📖 [Читать полный лонгрид](${gistUrl})\n\n`;
message += `⏱ Время чтения: ~${longreadData.metadata?.estimated_reading_time || 'N/A'}\n`;
message += `📚 Использовано источников: ${longreadData.metadata?.total_sources || 0}`;

// ✅ СОХРАНЯЕМ ВСЕ ДАННЫЕ для downstream nodes
return {
  json: {
    telegram_message: message,
    gist_url: gistUrl,
    title: title,
    markdown_content: markdown,
    longread_data: longreadData,
    original_articles: originalArticles,
    analyst_output: analystOutput
  }
};

const inputData = $input.first().json;
console.log('Full input:', JSON.stringify(inputData, null, 2));
const articles = inputData.articles || [];
if (!articles || articles.length === 0) {
  throw new Error('No articles received from webhook');
}

const formattedArticles = articles.map((article, index) => ({
  id: index + 1,
  title: article.title || article.scraped_title || article.rss_title || 'Untitled',  // ← ФИХ ЗДЕСЬ
  url: article.source_url,
  content: article.full_text,
  author: article.author,
  pubDate: article.pubDate,
  contentLength: article.full_text?.length || 0
}));

const analysisPrompt = `Проанализируй следующие ${formattedArticles.length} технологических новостей:

${formattedArticles.map(a => `
--- Статья #${a.id} ---
Заголовок: ${a.title}
URL: ${a.url}
Автор: ${a.author || 'Unknown'}
Дата: ${a.pubDate}
Длина контента: ${a.contentLength} символов

Содержание:
${a.content}
`).join('\n')}

Проанализируй их согласно инструкциям в System Prompt.
Верни результат в формате JSON согласно схеме.`;

return {
  json: {
    analysisPrompt,
    totalArticles: formattedArticles.length,
    articles: formattedArticles
  }
};

const longreadData = $('5. AI Longread Writer').first().json.output;

return {
  json: {
    description: longreadData.title,
    public: false,
    files: {
      "longread.md": {
        content: longreadData.markdown_content
      }
    }
  }
};

// Получаем данные из Send Telegram
const telegramResponse = $input.first().json;
const telegramMessage = telegramResponse.result || telegramResponse;

// Получаем сохранённые данные из Prepare Telegram Summary (через Send Telegram)
const prepareTelegramData = $('9. Prepare Telegram Summary').first().json;

const gistUrl = prepareTelegramData.gist_url;
const longreadData = prepareTelegramData.longread_data;
const originalArticles = prepareTelegramData.original_articles;
const analystOutput = prepareTelegramData.analyst_output;

// Формируем news_list: джойним selected_articles + originalArticles
const newsList = analystOutput.selected_articles.map(selected => {
  const originalArticle = originalArticles.find(a => a.id === selected.id);
  if (!originalArticle) {
    throw new Error(`Article with id ${selected.id} not found in originalArticles`);
  }
  return {
    id: selected.id,
    title: originalArticle.title || 'Untitled',
    url: originalArticle.url || '',
    summary: selected.reason || '',
    full_text: originalArticle.content || ''
  };
});

// Возвращаем ДВА item'а
return [
  // Item 0: для Airtable
  {
    json: {
      storage_type: 'airtable',
      created_at: longreadData.metadata?.created_at || new Date().toISOString().split('T')[0],
      gist_url: gistUrl,
      topics_covered: longreadData.metadata?.topics_covered || [],
      markdown_content: longreadData.markdown_content,
      telegram_message_id: telegramMessage.message_id
    }
  },
  // Item 1: для Supabase
  {
    json: {
      storage_type: 'supabase',
      telegram_message_id: telegramMessage.message_id,
      telegram_chat_id: telegramMessage.chat.id,
      message_type: 'longread',
      task_id: null,
      content_data: {
        title: longreadData.title,
        gist_url: gistUrl,
        longread_markdown: longreadData.markdown_content,
        news_list: newsList,
        metadata: longreadData.metadata
      }
    }
  }
];
